@strawberry.type
class Product:
    id: int
    name: str
    description: Optional[str]
    price: str

    @strawberry.field
    def seller(self, info) -> Seller:
        model: ProductModel = info.context["product_model_map"][self.id]
        return Seller(
            id=model.seller.id,
            name=model.seller.name,
            email=model.seller.email,
        )

    @strawberry.field
    def category(self, info) -> Category:
        model: ProductModel = info.context["product_model_map"][self.id]
        return Category(
            id=model.category.id,
            name=model.category.name,
            description=model.category.description,
        )

    @strawberry.field
    def reviews(self, info) -> List[Review]:
        model: ProductModel = info.context["product_model_map"][self.id]
        return [
            Review(
                id=review.id,
                author_name=review.author_name,
                rating=review.rating,
                comment=review.comment,
                created_at=review.created_at,
            )
            for review in model.reviews
        ]

    @strawberry.field
    def images(self, info) -> List[Image]:
        model: ProductModel = info.context["product_model_map"][self.id]
        return [
            Image(
                id=image.id,
                url=image.url,
                alt_text=image.alt_text,
            )
            for image in model.images
        ]


def to_product_type(model: ProductModel) -> Product:
    return Product(
        id=model.id,
        name=model.name,
        description=model.description,
        price=str(model.price),
    )


@strawberry.type
class Query:
    @strawberry.field
    def products(
        self,
        info,
        seller_id: Optional[int] = None,
        category_id: Optional[int] = None,
    ) -> List[Product]:
        with Session(engine) as session:
            stmt = (
                select(ProductModel)
                .options(
                    selectinload(ProductModel.seller),
                    selectinload(ProductModel.category),
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.images),
                )
                .order_by(ProductModel.id)
            )

            if seller_id is not None:
                stmt = stmt.where(ProductModel.seller_id == seller_id)
            if category_id is not None:
                stmt = stmt.where(ProductModel.category_id == category_id)

            models = list(session.scalars(stmt).all())
            info.context["product_model_map"] = {model.id: model for model in models}
            return [to_product_type(model) for model in models]

    @strawberry.field
    def product(self, info, id: int) -> Optional[Product]:
        with Session(engine) as session:
            stmt = (
                select(ProductModel)
                .options(
                    selectinload(ProductModel.seller),
                    selectinload(ProductModel.category),
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.images),
                )
                .where(ProductModel.id == id)
            )
            model = session.scalar(stmt)
            if model is None:
                return None
            info.context["product_model_map"] = {model.id: model}
            return to_product_type(model)

    @strawberry.field
    def sellers(self) -> List[Seller]:
        with Session(engine) as session:
            models = session.scalars(select(SellerModel).order_by(SellerModel.id)).all()
            return [Seller(id=m.id, name=m.name, email=m.email) for m in models]

    @strawberry.field
    def categories(self) -> List[Category]:
        with Session(engine) as session:
            models = session.scalars(select(CategoryModel).order_by(CategoryModel.id)).all()
            return [Category(id=m.id, name=m.name, description=m.description) for m in models]


schema = strawberry.Schema(query=Query)


